import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Loader } from '@googlemaps/js-api-loader';

const Dashboard = () => {
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [waypoints] = useState([]);
  const [routes, setRoutes] = useState([]);
  const [fuelConsumption, setFuelConsumption] = useState(10); // km/l
  const [fuelPrice, setFuelPrice] = useState(5); // R$/l
  const [map, setMap] = useState(null);
  const [selectedRoute, setSelectedRoute] = useState(null);

  useEffect(() => {
    const loader = new Loader({
      apiKey: process.env.REACT_APP_GOOGLE_MAPS_API_KEY,
      version: 'weekly',
      libraries: ['geometry']
    });
    loader.load().then(() => {
      const mapInstance = new window.google.maps.Map(document.getElementById('map'), {
        center: { lat: -23.5505, lng: -46.6333 },
        zoom: 8,
      });
      setMap(mapInstance);
    }).catch((err) => {
      console.error('Google Maps load error', err);
      alert('Falha ao carregar o Google Maps. Verifique a chave da API.');
    });
  }, []);

  const calculateRoutes = async () => {
    try {
      const res = await axios.post('/api/routes', {
        origin,
        destination,
        waypoints,
        avoidTolls: false,
        avoidHighways: false,
      });
      const routesWithCost = res.data.map(route => ({
        ...route,
        cost: (route.distance / fuelConsumption) * fuelPrice,
      }));
      setRoutes(routesWithCost);
      displayRoutes(routesWithCost);
    } catch (err) {
      alert('Error calculating routes');
    }
  };

  const displayRoutes = (routes) => {
    if (!map || !window.google) return;
    routes.forEach((route, index) => {
      const path = window.google.maps.geometry.encoding.decodePath(route.polyline);
      const polyline = new window.google.maps.Polyline({
        path,
        strokeColor: index === 0 ? '#FF0000' : '#0000FF',
        strokeOpacity: 0.8,
        strokeWeight: 2,
        map,
      });
      polyline.addListener('click', () => setSelectedRoute(route));
    });
  };

  const saveRoute = async (route) => {
    try {
      await axios.post('/api/history', route, {
        headers: { Authorization: localStorage.getItem('token') },
      });
      alert('Route saved');
    } catch (err) {
      alert('Error saving route');
    }
  };

  return (
    <div className="dashboard">
      <h1>RouteLog</h1>
      <div className="form">
        <input type="text" placeholder="Origin" value={origin} onChange={(e) => setOrigin(e.target.value)} />
        <input type="text" placeholder="Destination" value={destination} onChange={(e) => setDestination(e.target.value)} />
        <input type="number" placeholder="Fuel Consumption (km/l)" value={fuelConsumption} onChange={(e) => setFuelConsumption(e.target.value)} />
        <input type="number" placeholder="Fuel Price (R$/l)" value={fuelPrice} onChange={(e) => setFuelPrice(e.target.value)} />
        <button onClick={calculateRoutes}>Calculate Routes</button>
      </div>
      <div id="map" style={{ height: '400px', width: '100%' }}></div>
      {routes.length > 0 && (
        <div className="routes">
          {routes.map((route, index) => (
            <div key={index} className={`route ${selectedRoute === route ? 'selected' : ''}`}>
              <h3>Route {index + 1}</h3>
              <p>Distance: {route.distance.toFixed(2)} km</p>
              <p>Time: {route.duration.toFixed(2)} min</p>
              <p>Cost: R$ {route.cost.toFixed(2)}</p>
              <p>Cities: {route.cities.join(', ')}</p>
              <button onClick={() => saveRoute(route)}>Save Route</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
